 1→import { Hono } from 'hono';
 2→import type { Env, ApiKey } from '../types';
 3→import { sha256, requireApiKey } from '../middleware/auth';
 4→import { createApiKey, getTokenUsage } from '../db/queries';
 5→
 6→const keys = new Hono<{ Bindings: Env; Variables: { apiKey: ApiKey } }>();
 7→
 8→/** POST /api/v1/keys — create a new API key (authenticated with SECRET_KEY) */
 9→keys.post('/api/v1/keys', async (c) => {
10→  const body = await c.req.json<{ secret_key: string; name?: string; max_token_usage?: number }>();
11→
12→  if (!body.secret_key || body.secret_key !== c.env.SECRET_KEY) {
13→    return c.json({ detail: 'Invalid secret key' }, 401);
14→  }
15→
16→  // Generate sk-{64 random chars}
17→  const raw = `${crypto.randomUUID().replace(/-/g, '')}${crypto.randomUUID().replace(/-/g, '')}`;
18→  const apiKeyValue = `sk-${raw}`;
19→  const apiKeyHash = await sha256(apiKeyValue);
20→
21→  const record = await createApiKey(c.env.DB, apiKeyValue, apiKeyHash, body.name ?? null, body.max_token_usage);
22→
23→  return c.json({
24→    api_key: record.api_key,
25→    name: record.name,
26→    max_token_usage: record.max_token_usage,
27→    created_at: record.created_at,
28→    message: 'API key created successfully. Save this key as it won\'t be shown again.',
29→  });
30→});
31→
32→/** GET /api/v1/keys/usage — get token usage for the authenticated key */
33→keys.get('/api/v1/keys/usage', requireApiKey, async (c) => {
34→  const apiKey = c.var.apiKey;
35→  const usage = await getTokenUsage(c.env.DB, apiKey.id);
36→
37→  return c.json({
38→    api_key_id: apiKey.id,
39→    name: apiKey.name,
40→    is_active: apiKey.is_active === 1,
41→    max_token_usage: apiKey.max_token_usage,
42→    tokens_in: usage?.tokens_in ?? 0,
43→    tokens_out: usage?.tokens_out ?? 0,
44→    total_tokens: (usage?.tokens_in ?? 0) + (usage?.tokens_out ?? 0),
45→    request_count: usage?.request_count ?? 0,
46→    last_used_at: usage?.last_used_at ?? null,
47→  });
48→});
49→
50→export default keys;
