 96→        _quests[questId] = QuestEscrow({
 97→            sponsor: msg.sender,
 98→            token: token,
 99→            deposited: actualReceived,
100→            distributed: 0,
101→            refunded: 0,
102→            createdAt: uint64(block.timestamp),
103→            expiresAt: expiresAt,
104→            cancelled: false
